func TestDeque_ConcurrentPushPopSteal(t *testing.T) {
	const total = 2000
	const stealers = 4

	d := NewDeque()
	results := make(chan int, total*2)
	errs := make(chan error, stealers+2)
	start := make(chan struct{})
	var producerDone atomic.Bool
	var stop atomic.Bool
	var wg sync.WaitGroup

	wg.Add(1)
	go func() {
		defer wg.Done()
		<-start
		for i := 0; i < total; i++ {
			if stop.Load() {
				return
			}
			d.PushBottom(i)
			if i%17 == 0 {
				runtime.Gosched()
			}
		}
		producerDone.Store(true)
	}()

	consume := func(name string, fn func() (interface{}, bool)) {
		defer wg.Done()
		<-start
		for {
			if stop.Load() {
				return
			}
			item, ok := fn()
			if ok {
				v, ok := item.(int)
				if !ok {
					errs <- fmt.Errorf("%s received non-int item %T", name, item)
					stop.Store(true)
					return
				}
				results <- v
				continue
			}
			if producerDone.Load() && d.IsEmpty() {
				return
			}
			runtime.Gosched()
		}
	}

	wg.Add(1)
	go consume("owner", d.PopBottom)
	for i := 0; i < stealers; i++ {
		wg.Add(1)
		go consume(fmt.Sprintf("thief-%d", i), d.StealTop)
	}

	close(start)
	done := make(chan struct{})
	go func() {
		wg.Wait()
		close(done)
	}()

	select {
	case <-done:
	case <-time.After(5 * time.Second):
		stop.Store(true)
		t.Fatal("concurrent push/pop/steal did not finish")
	}

	close(results)
	close(errs)

	for err := range errs {
		if err != nil {
			t.Fatal(err)
		}
	}

	seen := make(map[int]bool, total)
	for item := range results {
		if item < 0 || item >= total {
			t.Fatalf("consumed item out of range: %d", item)
		}
		if seen[item] {
			t.Fatalf("consumed duplicate item: %d", item)
		}
		seen[item] = true
	}
	if len(seen) != total {
		t.Fatalf("expected to consume %d unique items, got %d", total, len(seen))
	}
	if !d.IsEmpty() {
		t.Fatal("deque should be empty after all items are consumed")
	}
}

