func TestSWIM_HistoryBoundAtCap(t *testing.T) {
	ml := NewMemberList("n1")
	ml.Alive("n2", 0, nil)
	cfg := DefaultSWIMConfig()
	sd := NewSWIMDetector(ml, cfg, alwaysAck, alwaysNackIndirect, 42)

