		sd.RunProbeRound()
	}

	h := sd.History()
	if len(h) != defaultProbeHistoryLimit {
		t.Fatalf("expected history length at cap %d, got %d", defaultProbeHistoryLimit, len(h))
	}
	if h[0].Round != 1 {
		t.Fatalf("expected first retained round 1 at cap boundary, got %d", h[0].Round)
	}
	if h[len(h)-1].Round != defaultProbeHistoryLimit {
		t.Fatalf("expected last retained round %d, got %d", defaultProbeHistoryLimit, h[len(h)-1].Round)
	}
}

func TestSWIM_HistoryEvictsOldestPastCap(t *testing.T) {
