   145	// RunGossipRound executes one round of gossip for all nodes.
   146	// Each node picks fanout peers and performs push-pull, subject to
   147	// network conditions (partitions, packet loss).
   148	func (ns *NetworkSim) RunGossipRound() SimRoundResult {
   149		ns.mu.Lock()
   150		defer ns.mu.Unlock()
   151		ns.clock++
   152	
   153		var result SimRoundResult
   154		peerList := ns.peerList()
   155	
   156		for nodeID, proto := range ns.nodes {
   157			sel := gossip.NewRandomPeerSelector(ns.rng.Int63())
   158			peers := sel.SelectPeers(peerList, nodeID, proto.Fanout())
   159	
   160			for _, peerID := range peers {
   161				if ns.isPartitioned(nodeID, peerID) {
   162					result.Blocked++
   163					continue
   164				}
   165				if ns.dropRate > 0 && ns.rng.Float64() < ns.dropRate {
   166					result.Dropped++
   167					continue
   168				}
   169				peerStore, ok := ns.stores[peerID]
   170				if !ok {
   171					continue
   172				}
   173				exchange := proto.PushPull(peerStore)
   174				result.Exchanges++
   175				result.PushedTotal += exchange.PushedTo
   176				result.PulledTotal += exchange.PulledFrom
   177	
   178				ns.recordEvent(Event{
   179					Time:    ns.clock,
   180					Type:    EventGossip,
   181					Source:  nodeID,
   182					Target:  peerID,
   183					Payload: exchange,
   184				})
   185			}
   186		}
   187		return result
   188	}
