   263	func storeToTree(store *gossip.StateStore) *merkle.Tree {
   264		tree := merkle.NewTree()
   265		entries := make(map[string][]byte)
   266		for _, key := range store.Keys() {
   267			v, ok := store.Get(key)
   268			if ok {
   269				entries[key] = v
   270			}
   271		}
   272		tree.PutBatch(entries)
   273		return tree
   274	}
