   186	func TestNetworkSim_SplitBrainRecovery(t *testing.T) {
   187		ns := NewNetworkSim(42)
   188		// Create two groups: {n0,n1} and {n2,n3}
   189		for i := 0; i < 4; i++ {
   190			ns.AddNode(fmt.Sprintf("n%d", i), 2)
   191		}
   192	
   193		// Partition into two groups
   194		ns.Partition("n0", "n2")
   195		ns.Partition("n0", "n3")
   196		ns.Partition("n1", "n2")
   197		ns.Partition("n1", "n3")
   198	
   199		// Each group writes different data
   200		ns.GetStore("n0").Put("group-a", []byte("alpha"))
   201		ns.GetStore("n2").Put("group-b", []byte("beta"))
   202	
   203		// Let each group gossip internally
   204		for i := 0; i < 10; i++ {
   205			ns.RunGossipRound()
   206		}
   207	
   208		// Heal all partitions
   209		ns.Heal("n0", "n2")
   210		ns.Heal("n0", "n3")
   211		ns.Heal("n1", "n2")
   212		ns.Heal("n1", "n3")
   213	
   214		// Gossip should converge all nodes
   215		for i := 0; i < 30; i++ {
   216			ns.RunGossipRound()
   217			if ns.Converged() {
   218				// Verify all data is present
   219				for j := 0; j < 4; j++ {
   220					store := ns.GetStore(fmt.Sprintf("n%d", j))
   221					_, ok1 := store.Get("group-a")
   222					_, ok2 := store.Get("group-b")
   223					if !ok1 || !ok2 {
   224						t.Fatalf("n%d missing data after split-brain recovery", j)
   225					}
   226				}
   227				return
   228			}
   229		}
   230		t.Fatal("split-brain recovery should converge")
   231	}
